mapper.select:
SELECT t.id, t.provider_id, p.name as provider_name, t.trigger_type, t.status,
       t.start_time, t.end_time, t.duration, t.channel_count,
       t.error_message, t.raw_content, t.created_at, t.updated_at
FROM m3u8_refresh_task t
LEFT JOIN m3u8_providers p ON t.provider_id = p.id
WHERE t.deleted = 0

    AND p.name LIKE '%' || #{providerName} || '%'


    AND t.trigger_type = #{triggerType}


    AND t.status = #{status}


    AND t.created_at >= #{startTime}


    AND t.created_at <= #{endTime}

ORDER BY t.id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM m3u8_refresh_task t
LEFT JOIN m3u8_providers p ON t.provider_id = p.id
WHERE t.deleted = 0

    AND p.name LIKE '%' || #{providerName} || '%'


    AND t.trigger_type = #{triggerType}


    AND t.status = #{status}


    AND t.created_at >= #{startTime}


    AND t.created_at <= #{endTime}
